fs.writeFileSync(tempPath, JSON.stringify({ size: content.length, timestamp: Date.now() }));

// Read temp file
const tempData = JSON.parse(fs.readFileSync(tempPath, 'utf-8'));

// Delete temp file
fs.unlinkSync(tempPath);

